  3	import {
  4	  DescriptionList,
  5	  DescriptionListTerm,
  6	  DescriptionListDescription,
  7	  DescriptionListGroup,
  8	  Modal,
  9	  ModalVariant,
 10	  Title
 11	} from '@patternfly/react-core';
 12	import { helpers } from '../../helpers';
 13	import { type ReportAggregateDiagnosticsType, type ReportAggregateResultsType } from '../../types/types';
 14	
 15	type PartialReportsAggregateResponse = {
 16	  results?: Partial<ReportAggregateResultsType>;
 17	  diagnostics?: Partial<ReportAggregateDiagnosticsType>;
 18	};
 19	
 20	type Report = {
 21	  id: number;
 22	  report: PartialReportsAggregateResponse;
 23	};
 24	
 25	interface ShowAggregateReportModalProps {
 26	  isOpen: boolean;
 27	  report?: Report;
 28	  onClose?: () => void;
 29	  actions?: React.ReactNode[];
 30	}
 31	
 32	/**
 33	 * A filter list for displaying specific report properties. Order does not represent display sort.
 34	 */
 35	const statsFilter = [
 36	  'ansible_hosts_all',
 37	  'instances_hypervisor',
 38	  'instances_physical',
 39	  'instances_virtual',
 40	  'openshift_cores',
 41	  'socket_pairs',
 42	  'system_creation_date_average',
 43	  'vmware_hosts',
 44	  'inspect_result_status_failed',
 45	  'inspect_result_status_success',
 46	  'inspect_result_status_unknown',
 47	  'inspect_result_status_unreachable',
 48	  'missing_pem_files',
 49	  'missing_system_creation_date',
 50	  'missing_system_purpose'
 51	];
 52	
 53	/**
 54	 * Apply list format, sort, and filter to report
 55	 */
 56	const formatSortFilterReportStats = (
 57	  report: PartialReportsAggregateResponse = {},
 58	  { filter = statsFilter }: { filter?: string[] } = {}
 59	) => {
 60	  const { results: resultStats = {}, diagnostics: diagnosticStats = {} } = report;
 61	
 62	  return [...Object.entries(resultStats || {}), ...Object.entries(diagnosticStats || {})]
 63	    .filter(([key]) => filter.includes(key))
 64	    .sort(([aKey], [bKey]) => aKey.localeCompare(bKey))
 65	    .map(([key, value]) => {
 66	      const updatedValue = (
 67	        (key === 'system_creation_date_average' && helpers.formatDate(value as Date, 'DD MMMM Y')) ||
 68	        value
 69	      )?.toString();
 70	
 71	      return [key, updatedValue];
 72	    });
 73	};
 74	
 75	/**
 76	 * Modal display for report summary stats.
 77	 */
 78	const ShowAggregateReportModal: React.FC<ShowAggregateReportModalProps> = ({
 79	  isOpen,
 80	  report,
 81	  onClose = Function.prototype,
 82	  actions
 83	}) => {
 84	  const { t } = useTranslation();
 85	  const stats = formatSortFilterReportStats(report?.report);
 86	
 87	  return (
 88	    <Modal
 89	      variant={ModalVariant.small}
 90	      title={t('modal.title', { context: 'scan-summary' })}
 91	      isOpen={isOpen}
 92	      onClose={() => onClose()}
 93	      {...(actions && { actions })}
 94	    >
 95	      <Title className="pf-v6-u-mb-lg" headingLevel="h2" size="md">
 96	        {t('modal.subtitle', { context: 'scan-id', value: report?.id })}
 97	      </Title>
 98	      <DescriptionList isHorizontal isFluid isCompact>
 99	        {stats.map(([key, value]) => {
100	          return (
101	            <DescriptionListGroup data-ouia-component-id={key} key={key}>
102	              <DescriptionListTerm>{t('modal.label', { context: key })}</DescriptionListTerm>
103	              <DescriptionListDescription>{value}</DescriptionListDescription>
104	            </DescriptionListGroup>
105	          );
106	        })}
107	      </DescriptionList>
108	    </Modal>
109	  );
110	};
111	
112	export {
113	  ShowAggregateReportModal as default,
114	  ShowAggregateReportModal,
115	  formatSortFilterReportStats,
116	  statsFilter,
117	  type PartialReportsAggregateResponse,
118	  type Report,
119	  type ShowAggregateReportModalProps
120	};

